from flask import Flask, request, jsonify
from pymongo import MongoClient, ASCENDING, DESCENDING
from bson import ObjectId
from datetime import datetime
import json

app = Flask(__name__)

client = MongoClient('mongodb://localhost:27017/')
db = client['content_management_system']
users_collection = db['users']
content_collection = db['content']

users_collection.create_index([('email', ASCENDING)], unique=True)
users_collection.create_index([('username', ASCENDING)], unique=True)
content_collection.create_index([('author_id', ASCENDING)])
content_collection.create_index([('created_at', DESCENDING)])
content_collection.create_index([('status', ASCENDING)])
content_collection.create_index([('tags', ASCENDING)])

class JSONEncoder(json.JSONEncoder):
    def default(self, obj):
        if isinstance(obj, ObjectId):
            return str(obj)
        if isinstance(obj, datetime):
            return obj.isoformat()
        return super(JSONEncoder, self).default(obj)

app.json_encoder = JSONEncoder

@app.route('/users', methods=['POST'])
def create_user():
    data = request.get_json()
    
    user = {
        'username': data.get('username'),
        'email': data.get('email'),
        'first_name': data.get('first_name'),
        'last_name': data.get('last_name'),
        'bio': data.get('bio', ''),
        'role': data.get('role', 'user'),
        'avatar_url': data.get('avatar_url', ''),
        'created_at': datetime.utcnow(),
        'updated_at': datetime.utcnow(),
        'metadata': data.get('metadata', {})
    }
    
    try:
        result = users_collection.insert_one(user)
        user['_id'] = result.inserted_id
        return jsonify({'success': True, 'user': user}), 201
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 400

@app.route('/users/<user_id>', methods=['GET'])
def get_user(user_id):
    try:
        user = users_collection.find_one({'_id': ObjectId(user_id)})
        if user:
            return jsonify({'success': True, 'user': user}), 200
        return jsonify({'success': False, 'error': 'User not found'}), 404
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 400

@app.route('/users/<user_id>', methods=['PUT'])
def update_user(user_id):
    data = request.get_json()
    
    update_data = {
        'updated_at': datetime.utcnow()
    }
    
    allowed_fields = ['first_name', 'last_name', 'bio', 'role', 'avatar_url', 'metadata']
    for field in allowed_fields:
        if field in data:
            update_data[field] = data[field]
    
    try:
        result = users_collection.update_one(
            {'_id': ObjectId(user_id)},
            {'$set': update_data}
        )
        
        if result.matched_count:
            user = users_collection.find_one({'_id': ObjectId(user_id)})
            return jsonify({'success': True, 'user': user}), 200
        return jsonify({'success': False, 'error': 'User not found'}), 404
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 400

@app.route('/users/<user_id>', methods=['DELETE'])
def delete_user(user_id):
    try:
        result = users_collection.delete_one({'_id': ObjectId(user_id)})
        if result.deleted_count:
            return jsonify({'success': True, 'message': 'User deleted'}), 200
        return jsonify({'success': False, 'error': 'User not found'}), 404
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 400

@app.route('/users', methods=['GET'])
def list_users():
    page = int(request.args.get('page', 1))
    limit = int(request.args.get('limit', 10))
    skip = (page - 1) * limit
    
    query = {}
    if request.args.get('role'):
        query['role'] = request.args.get('role')
    
    users = list(users_collection.find(query).skip(skip).limit(limit))
    total = users_collection.count_documents(query)
    
    return jsonify({
        'success': True,
        'users': users,
        'page': page,
        'limit': limit,
        'total': total,
        'pages': (total + limit - 1) // limit
    }), 200

@app.route('/content', methods=['POST'])
def create_content():
    data = request.get_json()
    
    content = {
        'title': data.get('title'),
        'body': data.get('body'),
        'author_id': ObjectId(data.get('author_id')),
        'status': data.get('status', 'draft'),
        'tags': data.get('tags', []),
        'category': data.get('category', ''),
        'views': 0,
        'likes': 0,
        'created_at': datetime.utcnow(),
        'updated_at': datetime.utcnow(),
        'published_at': None,
        'metadata': data.get('metadata', {})
    }
    
    if content['status'] == 'published':
        content['published_at'] = datetime.utcnow()
    
    try:
        result = content_collection.insert_one(content)
        content['_id'] = result.inserted_id
        return jsonify({'success': True, 'content': content}), 201
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 400

@app.route('/content/<content_id>', methods=['GET'])
def get_content(content_id):
    try:
        content = content_collection.find_one({'_id': ObjectId(content_id)})
        if content:
            content_collection.update_one(
                {'_id': ObjectId(content_id)},
                {'$inc': {'views': 1}}
            )
            content['views'] += 1
            return jsonify({'success': True, 'content': content}), 200
        return jsonify({'success': False, 'error': 'Content not found'}), 404
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 400

@app.route('/content/<content_id>', methods=['PUT'])
def update_content(content_id):
    data = request.get_json()
    
    update_data = {
        'updated_at': datetime.utcnow()
    }
    
    allowed_fields = ['title', 'body', 'status', 'tags', 'category', 'metadata']
    for field in allowed_fields:
        if field in data:
            update_data[field] = data[field]
    
    if data.get('status') == 'published':
        content = content_collection.find_one({'_id': ObjectId(content_id)})
        if content and not content.get('published_at'):
            update_data['published_at'] = datetime.utcnow()
    
    try:
        result = content_collection.update_one(
            {'_id': ObjectId(content_id)},
            {'$set': update_data}
        )
        
        if result.matched_count:
            content = content_collection.find_one({'_id': ObjectId(content_id)})
            return jsonify({'success': True, 'content': content}), 200
        return jsonify({'success': False, 'error': 'Content not found'}), 404
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 400

