@app.route('/search/content', methods=['GET'])
def search_content():
    search_term = request.args.get('q', '')
    
    query = {
        '$or': [
            {'title': {'$regex': search_term, '$options': 'i'}},
            {'body': {'$regex': search_term, '$options': 'i'}},
            {'tags': {'$regex': search_term, '$options': 'i'}}
        ]
    }
    
    page = int(request.args.get('page', 1))
    limit = int(request.args.get('limit', 10))
    skip = (page - 1) * limit
    
    contents = list(content_collection.find(query).skip(skip).limit(limit))
    total = content_collection.count_documents(query)
    
    return jsonify({
        'success': True,
        'content': contents,
        'page': page,
        'limit': limit,
        'total': total,
        'pages': (total + limit - 1) // limit
    }), 200

@app.route('/analytics/content-by-author', methods=['GET'])
def content_by_author():
    pipeline = [
        {
            '$group': {
                '_id': '$author_id',
                'total_content': {'$sum': 1},
                'total_views': {'$sum': '$views'},
                'total_likes': {'$sum': '$likes'},
                'published_content': {
                    '$sum': {'$cond': [{'$eq': ['$status', 'published']}, 1, 0]}
                },
                'draft_content': {
                    '$sum': {'$cond': [{'$eq': ['$status', 'draft']}, 1, 0]}
                }
            }
        },
        {
            '$lookup': {
                'from': 'users',
                'localField': '_id',
                'foreignField': '_id',
                'as': 'author'
            }
        },
        {
            '$unwind': '$author'
        },
        {
            '$project': {
                'author_id': '$_id',
                'author_name': '$author.username',
                'author_email': '$author.email',
                'total_content': 1,
                'total_views': 1,
                'total_likes': 1,
                'published_content': 1,
                'draft_content': 1,
                'avg_views_per_content': {'$divide': ['$total_views', '$total_content']},
                'avg_likes_per_content': {'$divide': ['$total_likes', '$total_content']}
            }
        },
        {
            '$sort': {'total_content': -1}
        }
    ]
    
    results = list(content_collection.aggregate(pipeline))
    return jsonify({'success': True, 'analytics': results}), 200

