@app.route('/analytics/trending-content', methods=['GET'])
def trending_content():
    days = int(request.args.get('days', 7))
    limit = int(request.args.get('limit', 10))
    
    from datetime import timedelta
    since_date = datetime.utcnow() - timedelta(days=days)
    
    pipeline = [
        {
            '$match': {
                'created_at': {'$gte': since_date},
                'status': 'published'
            }
        },
        {
            '$addFields': {
                'engagement_score': {
                    '$add': [
                        {'$multiply': ['$views', 1]},
                        {'$multiply': ['$likes', 5]}
                    ]
                }
            }
        },
        {
            '$sort': {'engagement_score': -1}
        },
        {
            '$limit': limit
        },
        {
            '$lookup': {
                'from': 'users',
                'localField': 'author_id',
                'foreignField': '_id',
                'as': 'author'
            }
        },
        {
            '$unwind': '$author'
        },
        {
            '$project': {
                'title': 1,
                'views': 1,
                'likes': 1,
                'engagement_score': 1,
                'created_at': 1,
                'author_name': '$author.username',
                'tags': 1,
                'category': 1
            }
        }
    ]
    
    results = list(content_collection.aggregate(pipeline))
    return jsonify({'success': True, 'trending': results}), 200

