@app.route('/analytics/user-activity', methods=['GET'])
def user_activity():
    pipeline = [
        {
            '$lookup': {
                'from': 'content',
                'localField': '_id',
                'foreignField': 'author_id',
                'as': 'user_content'
            }
        },
        {
            '$project': {
                'username': 1,
                'email': 1,
                'role': 1,
                'created_at': 1,
                'total_content': {'$size': '$user_content'},
                'total_views': {'$sum': '$user_content.views'},
                'total_likes': {'$sum': '$user_content.likes'}
            }
        },
        {
            '$sort': {'total_content': -1}
        }
    ]
    
    results = list(users_collection.aggregate(pipeline))
    return jsonify({'success': True, 'user_activity': results}), 200

